// hooks/useFoodPolling.js
import { useEffect, useRef } from 'react';
import { useDispatch,useSelector } from 'react-redux';
import { applyPollUpdate } from './redux_utils/foodSlice';

function useFoodPolling(interval = 12000) {
  const dispatch = useDispatch();
  const timerRef = useRef(null);

  const selector = useSelector((state)=>state.cart.items)

  console.lo

  useEffect(() => {

    const poll = async () => {
      try {
        const res = await fetch(`http://localhost:3009`,{
          credentials:'include'
        });
        if (!res.ok) return;
        const data = await res.json();
        if (data.success) dispatch(applyPollUpdate(data));
      } 
      catch (err) {
        console.error('[useFoodPolling] fetch failed:', err);
      }
    };

    poll();
    timerRef.current = setInterval(poll, interval);

    return () => clearInterval(timerRef.current);
  }, [interval, dispatch]);
}

export function FoodPolling(){
    useFoodPolling(12000);
    return null;
}
